import benchPressImage from "./assets/bench-press.svg";
import inclineDumbbellPressImage from "./assets/incline-dumbbell-press.svg";
import type {
  ExerciseWithTaxonomy, MovementPattern, ExerciseAngle, ExerciseEquipment,
  ExerciseDifficulty, CustomExerciseType, MeasurementType, DraftSet,
  PerformanceMetric, ExerciseImplement
} from "./types";

export function makeExercise(
  id: string,
  name: string,
  primaryMuscle: string,
  secondaryMuscles: string[],
  movementPattern: MovementPattern,
  angle: ExerciseAngle,
  equipment: ExerciseEquipment,
  difficultyLevel: ExerciseDifficulty,
  exerciseType: CustomExerciseType,
  restTimer: string,
  howTo: string[],
  measurementType?: MeasurementType,
  performanceMetric?: PerformanceMetric,
  supportsExternalLoad?: boolean,
  implement?: ExerciseImplement,
): ExerciseWithTaxonomy {
  const img = (equipment === "dumbbell" || equipment === "cable" || equipment === "none" || equipment === "bodyweight")
    ? inclineDumbbellPressImage
    : benchPressImage;
  return {
    id,
    name,
    note: "",
    restTimer,
    goal: "hypertrophy",
    imageSrc: img,
    primaryMuscle,
    secondaryMuscles,
    howTo,
    history: [],
    draftSets: [
      { id: `${id}-1`, setType: "normal", weightInput: "", repsInput: "", rpeInput: "", done: false, failed: false },
      { id: `${id}-2`, setType: "normal", weightInput: "", repsInput: "", rpeInput: "", done: false, failed: false },
      { id: `${id}-3`, setType: "normal", weightInput: "", repsInput: "", rpeInput: "", done: false, failed: false }
    ],
    movementPattern,
    angle,
    equipment,
    difficultyLevel,
    exerciseType,
    ...(measurementType       ? { measurementType }       : {}),
    ...(performanceMetric     ? { performanceMetric }     : {}),
    ...(supportsExternalLoad !== undefined ? { supportsExternalLoad } : {}),
    ...(implement             ? { implement }             : {}),
  };
}

